// src/utils/jwt.ts
import jwt from "jsonwebtoken";
var createToken = (payload, secret, expiresIn) => {
  const token = jwt.sign(
    payload,
    secret,
    {
      expiresIn
    }
  );
  return token;
};
var verifyToken = (token, secret) => {
  try {
    const verifiedToken = jwt.verify(token, secret);
    return {
      success: true,
      data: verifiedToken
    };
  } catch (error) {
    console.log("Token verification failed:", error);
    return {
      success: false,
      error: error.message
    };
  }
};
var jwtUtils = {
  createToken,
  verifyToken
};

// src/middlewares/auth.ts
var auth = (...requiredRoles) => {
  return catchAsync(async (req, res, next) => {
    const token = req.cookies?.accessToken ? req.cookies.accessToken : req.headers.authorization?.startsWith("Bearer ") ? req.headers.authorization?.split(" ")[1] : req.headers.authorization;
    if (!token) {
      throw new AppError_default(httpStatus3.UNAUTHORIZED, "You are not logged in. Please log in first to access this resource.");
    }
    const verifiedToken = jwtUtils.verifyToken(token, config_default.jwt_access_secret);
    if (!verifiedToken.success) {
      throw new AppError_default(httpStatus3.UNAUTHORIZED, verifiedToken.error || "Invalid or expired token. Please login again.");
    }
    const { id, email, name, role } = verifiedToken.data;
    if (requiredRoles.length && !requiredRoles.includes(role)) {
      throw new AppError_default(httpStatus3.FORBIDDEN, `Forbidden. Only ${requiredRoles.join(", ")} can access this resource.`);
    }
    const user = await prisma.user.findUnique({
      where: {
        id,
        email,
        name,
        role
      },
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
        isSuspended: true
      }
    });
    if (!user) {
      throw new AppError_default(httpStatus3.NOT_FOUND, "User not found. Please log in again.");
    }
    if (user.isSuspended) {
      throw new AppError_default(httpStatus3.FORBIDDEN, "Your account has been suspended. Please contact our support.");
    }
    req.user = {
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role
    };
    next();
  });
};

