// src/modules/auth/auth.service.ts
import bcrypt2 from "bcryptjs";
import httpStatus4 from "http-status";
var loginUser = async (payload) => {
  const { email, password } = payload;
  const user = await prisma.user.findUnique({
    where: { email }
  });
  if (!user) {
    throw new AppError_default(httpStatus4.NOT_FOUND, "User not found!");
  }
  if (user.isSuspended) {
    throw new AppError_default(httpStatus4.FORBIDDEN, "Your account has been suspended!");
  }
  const isPasswordValid = await bcrypt2.compare(password, user.password);
  if (!isPasswordValid) {
    throw new AppError_default(httpStatus4.UNAUTHORIZED, "Invalid credentials!");
  }
  const jwtPayload = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role
  };
  const accessToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_access_secret,
    config_default.jwt_access_expires_in
  );
  const refreshToken3 = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_refresh_secret,
    config_default.jwt_refresh_expires_in
  );
  return {
    accessToken,
    refreshToken: refreshToken3,
    user: {
      id: user.id,
      name: user.name,
      email: user.email,
      role: user.role,
      isSuspended: user.isSuspended,
      createdAt: user.createdAt,
      updatedAt: user.updatedAt
    }
  };
};
var refreshToken = async (refreshToken3) => {
  const verifiedRefreshToken = jwtUtils.verifyToken(
    refreshToken3,
    config_default.jwt_refresh_secret
  );
  if (!verifiedRefreshToken.success) {
    throw new AppError_default(httpStatus4.UNAUTHORIZED, verifiedRefreshToken.error || "Invalid or expired refresh token!");
  }
  const { id } = verifiedRefreshToken.data;
  const user = await prisma.user.findUnique({
    where: { id },
    select: {
      id: true,
      name: true,
      email: true,
      role: true,
      isSuspended: true
    }
  });
  if (!user) {
    throw new AppError_default(httpStatus4.NOT_FOUND, "User not found!");
  }
  if (user.isSuspended) {
    throw new AppError_default(httpStatus4.FORBIDDEN, "Your account has been suspended!");
  }
  const jwtPayload = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role
  };
  const newAccessToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_access_secret,
    config_default.jwt_access_expires_in
  );
  return {
    accessToken: newAccessToken,
    user: {
      id: user.id,
      name: user.name,
      email: user.email,
      role: user.role,
      isSuspended: user.isSuspended
    }
  };
};
var authService = {
  loginUser,
  refreshToken
};

