// src/modules/payment/payment.service.ts
var createPaymentIntoDB = async (rentalOrderId) => {
  const transactionResult = await prisma.$transaction(async (tx) => {
    const rental = await tx.rentalOrder.findUnique({
      where: { id: rentalOrderId },
      include: {
        customer: true,
        gearItem: true
      }
    });
    if (!rental) {
      throw new AppError_default(httpStatus15.NOT_FOUND, "Rental order not found!");
    }
    if (rental.status === "PAID") {
      throw new AppError_default(httpStatus15.CONFLICT, "Payment already completed for this rental!");
    }
    if (rental.status !== "PLACED" && rental.status !== "CONFIRMED") {
      throw new AppError_default(httpStatus15.BAD_REQUEST, `Cannot process payment for rental with status: ${rental.status}`);
    }
    const existingPayment = await tx.payment.findUnique({
      where: { rentalOrderId: rental.id }
    });
    if (existingPayment && existingPayment.status === "COMPLETED") {
      throw new AppError_default(httpStatus15.CONFLICT, "Payment already completed for this rental!");
    }
    const paymentIntent = await stripe.paymentIntents.create({
      amount: Math.round(rental.totalPrice * 100),
      currency: "usd",
      metadata: {
        rentalOrderId: rental.id,
        gearItemId: rental.gearItemId,
        userId: rental.customerId
      },
      description: `Rental payment for ${rental.gearItem.name}`,
      payment_method_types: ["card"],
      capture_method: "automatic"
    });
    if (existingPayment) {
      await tx.payment.update({
        where: { id: existingPayment.id },
        data: {
          transactionId: paymentIntent.id,
          amount: rental.totalPrice,
          status: "PENDING"
        }
      });
    } else {
      await tx.payment.create({
        data: {
          transactionId: paymentIntent.id,
          amount: rental.totalPrice,
          method: "STRIPE",
          rentalOrderId: rental.id,
          status: "PENDING"
        }
      });
    }
    return {
      clientSecret: paymentIntent.client_secret,
      transactionId: paymentIntent.id,
      amount: rental.totalPrice,
      status: paymentIntent.status || "pending"
    };
  });
  return transactionResult;
};
