var updateOrderStatusIntoDB = async (orderId, providerId, status) => {
  const order = await validateRental(orderId);
  if (order.gearItem.providerId !== providerId) {
    throw new AppError_default(httpStatus17.FORBIDDEN, "You are not authorized to update this order!");
  }
  const validTransitions = {
    PLACED: ["CONFIRMED", "CANCELLED"],
    CONFIRMED: ["PAID", "CANCELLED"],
    PAID: ["PICKED_UP", "CANCELLED"],
    PICKED_UP: ["RETURNED"],
    RETURNED: [],
    CANCELLED: []
  };
  if (!validTransitions[order.status]?.includes(status)) {
    throw new AppError_default(httpStatus17.BAD_REQUEST, `Invalid status transition from ${order.status} to ${status}!`);
  }
  const updatedOrder = await prisma.rentalOrder.update({
    where: { id: orderId },
    data: { status },
    include: {
      customer: {
        select: {
          id: true,
          name: true,
          email: true
        }
      },
      gearItem: {
        include: {
          category: true
        }
      },
      payment: true,
      review: true
    }
  });
  if (status === "RETURNED") {
    await prisma.gearItem.update({
      where: { id: order.gearItemId },
      data: {
        stockQuantity: { increment: 1 },
        availability: true
      }
    });
  }
  return updatedOrder;
};
